/**
 * pages/Login.jsx — Redesigned split-panel login page.
 */
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login, loading } = useAuth();
  const navigate = useNavigate();
  const [form, setForm]     = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [showPwd, setShowPwd] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.email)                          e.email    = 'Email is required.';
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email  = 'Enter a valid email.';
    if (!form.password) e.password = 'Password is required.';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    const result = await login(form.email, form.password);
    if (result.success) {
      toast.success('Welcome back!');
      navigate('/');
    } else {
      toast.error(result.message);
    }
  };

  return (
    <div className="min-h-screen flex">

      {/* ── Left panel: brand ── */}
      <div className="hidden lg:flex lg:w-1/2 flex-col items-center justify-center relative overflow-hidden"
           style={{ background: 'linear-gradient(145deg, #14532d 0%, #166534 40%, #15803d 100%)' }}>

        {/* Decorative circles */}
        <div className="absolute top-[-80px] left-[-80px] w-72 h-72 rounded-full opacity-10"
             style={{ background: 'radial-gradient(circle, #bbf7d0, transparent)' }} />
        <div className="absolute bottom-[-60px] right-[-60px] w-56 h-56 rounded-full opacity-10"
             style={{ background: 'radial-gradient(circle, #86efac, transparent)' }} />

        <div className="relative z-10 text-center px-12">
          {/* Logo badge */}
          <div className="w-24 h-24 rounded-full bg-white bg-opacity-15 flex items-center justify-center mx-auto mb-6 shadow-xl border border-white border-opacity-20">
            <span className="text-5xl">🥛</span>
          </div>

          <h1 className="text-4xl font-extrabold text-white leading-tight tracking-tight">
            Akshaya Farm Dairy
          </h1>
          <p className="text-green-200 text-base mt-3 font-light leading-relaxed">
            Complete Dairy Management System
          </p>

          {/* Feature pills */}
          <div className="mt-10 flex flex-col gap-3 text-left max-w-xs mx-auto">
            {[
              { icon: '🐄', text: 'Cattle health & tracking' },
              { icon: '🥛', text: 'Daily milk collection logs' },
              { icon: '💰', text: 'Sales & revenue insights' },
              { icon: '📦', text: 'Inventory management' },
            ].map(f => (
              <div key={f.text} className="flex items-center gap-3 bg-white bg-opacity-10 rounded-xl px-4 py-2.5 border border-white border-opacity-10">
                <span className="text-xl">{f.icon}</span>
                <span className="text-green-100 text-sm font-medium">{f.text}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom tagline */}
        <p className="absolute bottom-6 text-green-300 text-xs opacity-60">
          Powered by Akshaya Farms · 2026
        </p>
      </div>

      {/* ── Right panel: form ── */}
      <div className="w-full lg:w-1/2 flex items-center justify-center bg-gray-50 px-6 py-12">
        <div className="w-full max-w-sm">

          {/* Mobile logo (hidden on desktop) */}
          <div className="lg:hidden text-center mb-8">
            <div className="text-5xl mb-2">🥛</div>
            <h1 className="text-2xl font-bold text-gray-900">Akshaya Farm Dairy</h1>
          </div>

          {/* Form card */}
          <div className="bg-white rounded-2xl shadow-lg border border-gray-100 p-8">
            <div className="mb-7">
              <h2 className="text-2xl font-bold text-gray-900">Welcome back</h2>
              <p className="text-gray-500 text-sm mt-1">Sign in to your account to continue</p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              {/* Email */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1.5">Email address</label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-base">✉️</span>
                  <input
                    type="email"
                    value={form.email}
                    onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
                    className={`w-full pl-10 pr-4 py-2.5 border rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-green-500 transition
                      ${errors.email ? 'border-red-400 bg-red-50' : 'border-gray-200 bg-gray-50 focus:bg-white'}`}
                    placeholder="you@akshayafarm.com"
                    autoComplete="email"
                  />
                </div>
                {errors.email && <p className="text-red-500 text-xs mt-1.5 flex items-center gap-1">⚠ {errors.email}</p>}
              </div>

              {/* Password */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1.5">Password</label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-base">🔒</span>
                  <input
                    type={showPwd ? 'text' : 'password'}
                    value={form.password}
                    onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                    className={`w-full pl-10 pr-10 py-2.5 border rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-green-500 transition
                      ${errors.password ? 'border-red-400 bg-red-50' : 'border-gray-200 bg-gray-50 focus:bg-white'}`}
                    placeholder="••••••••"
                    autoComplete="current-password"
                  />
                  <button type="button" tabIndex={-1}
                    onClick={() => setShowPwd(p => !p)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 text-xs">
                    {showPwd ? '🙈' : '👁️'}
                  </button>
                </div>
                {errors.password && <p className="text-red-500 text-xs mt-1.5 flex items-center gap-1">⚠ {errors.password}</p>}
              </div>

              {/* Submit */}
              <button
                type="submit"
                disabled={loading}
                className="w-full py-3 rounded-lg font-semibold text-sm text-white transition-all
                           disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:shadow-lg active:scale-[0.99]"
                style={{ background: loading ? '#86efac' : 'linear-gradient(135deg, #16a34a 0%, #15803d 100%)' }}
              >
                {loading ? (
                  <span className="flex items-center justify-center gap-2">
                    <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin inline-block" />
                    Signing in…
                  </span>
                ) : 'Sign In →'}
              </button>
            </form>
          </div>

          <p className="text-center text-xs text-gray-400 mt-5 leading-relaxed">
            🔐 Account locked after 5 failed attempts.<br />Contact your Super Admin to unlock.
          </p>
        </div>
      </div>
    </div>
  );
}
